"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[409],{21(e,n,t){t.r(n),t.d(n,{assets:()=>r,contentTitle:()=>h,default:()=>c,frontMatter:()=>s,metadata:()=>o,toc:()=>d});var i=t(4848),a=t(8453);const s={},h="Chapter 3: The Cost of QCC",o={id:"mirror-realm/ch03",title:"Chapter 3: The Cost of QCC",description:"Taiwan Edition v9",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/mirror-realm/ch03.md",sourceDirName:"mirror-realm",slug:"/mirror-realm/ch03",permalink:"/MythogenEngine/en/docs/mirror-realm/ch03",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Chapter 2: Welcome to Mist Valley",permalink:"/MythogenEngine/en/docs/mirror-realm/ch02"},next:{title:"Chapter 4: Dictionary of Masks",permalink:"/MythogenEngine/en/docs/mirror-realm/ch04"}},r={},d=[{value:"Taiwan Edition v9",id:"taiwan-edition-v9",level:3}];function l(e){const n={em:"em",h1:"h1",h3:"h3",header:"header",hr:"hr",p:"p",strong:"strong",...(0,a.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(n.header,{children:(0,i.jsx)(n.h1,{id:"chapter-3-the-cost-of-qcc",children:"Chapter 3: The Cost of QCC"})}),"\n",(0,i.jsx)(n.h3,{id:"taiwan-edition-v9",children:"Taiwan Edition v9"}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Location: Mirror Realm \xb7 Emerald Isle Study (Parallel Universe No. 15)\nTime: OCT 1021\u2013MAR 1022\nProtagonist: Lin Zhao-ming"}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"It wasn't that someone told him to look into it."}),"\n",(0,i.jsx)(n.p,{children:'It was that he spoke out of turn and asked, "Why wouldn\'t it work?"'}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"The meeting was about planning for the second half of the year. Someone brought up QCC\u2014the Quantum Coordination Core, the electronic core management framework for the Mirror Screen terminals. Someone mentioned that integration was a direction they could take, but that electronic cores across different models couldn't be shared; each model had to be handled independently."}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming sat in his grid box, listening."}),"\n",(0,i.jsx)(n.p,{children:'"Why wouldn\'t it work?" he asked.'}),"\n",(0,i.jsx)(n.p,{children:"A beat of silence. Someone explained: The screw positions are different, there are variations in the port specifications, there are compatibility issues between old and new versions, each model has an independent design..."}),"\n",(0,i.jsx)(n.p,{children:'"But what about the electrical parameters?"'}),"\n",(0,i.jsx)(n.p,{children:"No one answered immediately."}),"\n",(0,i.jsx)(n.p,{children:"The meeting continued. But Lin Zhao-ming remembered that pause."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:'After the meeting ended, Cindy sent a message on Teams: "You have thoughts on the QCC integration? Go do some research on it."'}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming thought it was a sign of trust."}),"\n",(0,i.jsxs)(n.p,{children:['He didn\'t know that the true meaning of "go do some research on it" was: ',(0,i.jsx)(n.strong,{children:"Go explain why it cannot be done."})]}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"He ran the numbers."}),"\n",(0,i.jsxs)(n.p,{children:["The issue of sharing electronic cores was, on the surface, about screw positions. But practically, it was asking: If screw positions are the ",(0,i.jsx)(n.em,{children:"only"})," difference, and the other parameters are close enough, is it truly impossible?"]}),"\n",(0,i.jsx)(n.p,{children:"He dug through ALC to find the electronic core specs for every configuration and compared them one by one. Large capacity versus large capacity: the dimensions differed, but the charge and discharge curves were virtually identical. Small capacity versus small capacity: the port angles differed by a few degrees, but the electrical parameters were perfectly compatible."}),"\n",(0,i.jsx)(n.p,{children:"The math came out: It could be done."}),"\n",(0,i.jsx)(n.p,{children:'He wasn\'t the first person to run this math. But he was the first person unwilling to accept "no" as an answer.'}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"He started asking people."}),"\n",(0,i.jsx)(n.p,{children:'J said, "People have looked into this before, and the conclusion was that it can\'t be done. Go check ALC."'}),"\n",(0,i.jsx)(n.p,{children:'There was a document in ALC, and the conclusion was "Recommended to maintain current configuration." But the numbers were from several years ago.'}),"\n",(0,i.jsx)(n.p,{children:'He asked Old Xu. Old Xu said, "It\'s better if you ask the ODM."'}),"\n",(0,i.jsx)(n.p,{children:"He asked the ODM. The PM at the ODM, a guy named Qiang, replied with an email listing a bunch of technical limitations. Every single limitation had a name."}),"\n",(0,i.jsx)(n.p,{children:"He decoded them all, one by one."}),"\n",(0,i.jsx)(n.p,{children:'When he was done decoding: "Messy to implement" and "cannot be done" are two entirely different things.'}),"\n",(0,i.jsx)(n.p,{children:'He asked Qiang: "Can we run one complete test?"'}),"\n",(0,i.jsx)(n.p,{children:'Qiang paused for a moment. "Let me check the process."'}),"\n",(0,i.jsx)(n.p,{children:'A few days later: "Yes."'}),"\n",(0,i.jsx)(n.p,{children:"They ran it. The numbers came out, directly within the range Lin Zhao-ming had predicted."}),"\n",(0,i.jsx)(n.p,{children:"Sharing cores was viable."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"But what he didn't know was what was happening concurrently behind the scenes:"}),"\n",(0,i.jsx)(n.p,{children:"Before Qiang even took Lin Zhao-ming's call, he was already reporting directly to Cindy. Not in the official org chart\u2014but within the network beneath the table, built on years of a working relationship and unspoken understandings. Every person Lin Zhao-ming spoke to, every phone call he made, Cindy knew about it."}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming thought he was working independently."}),"\n",(0,i.jsx)(n.p,{children:"He had no idea that every step he took was being watched from under someone else's eyelids."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"After running the test, he organized the results into a report and sent it to Cindy."}),"\n",(0,i.jsx)(n.p,{children:"He waited a few days. No response."}),"\n",(0,i.jsx)(n.p,{children:'He sent a message to ask. Cindy said, "Received, I\'m taking a look."'}),"\n",(0,i.jsx)(n.p,{children:"He waited a few more days."}),"\n",(0,i.jsx)(n.p,{children:"He asked J. J said, \"Let Cindy look at it. Once she's done, she'll let you know.\""}),"\n",(0,i.jsx)(n.p,{children:"J was his mentor. The person who guided him on his very first day. J was also simultaneously Cindy's master, having guided her from the day she joined the workforce up until now."}),"\n",(0,i.jsx)(n.p,{children:"\"Let Cindy look at it. Once she's done, she'll let you know.\""}),"\n",(0,i.jsx)(n.p,{children:"At the time, it sounded neutral."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Then came that phone call from Qiang."}),"\n",(0,i.jsx)(n.p,{children:"Not an email, a phone call. Qiang called, his tone flat, but there was something hiding beneath the flatness."}),"\n",(0,i.jsx)(n.p,{children:'"Zhao-ming, that test from last time. There were no issues with the numbers. However\u2014"'}),"\n",(0,i.jsx)(n.p,{children:"A pause."}),"\n",(0,i.jsx)(n.p,{children:'"It\'s not convenient for me to discuss this further with you. You understand."'}),"\n",(0,i.jsx)(n.p,{children:'Lin Zhao-ming sat in his study. "What\'s the situation?"'}),"\n",(0,i.jsx)(n.p,{children:'"It\'s not convenient for me to say too much." It was the tone of a person who intimately knew they were caught in a vise. "If you want to keep pushing this, you\'ll have to figure out how to do it yourself. But from my end, I can\'t support you anymore."'}),"\n",(0,i.jsx)(n.p,{children:"He hung up."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"He sat there, staring at the black screen."}),"\n",(0,i.jsx)(n.p,{children:'It was "inconvenient" for Qiang because someone had told him it had to be inconvenient.'}),"\n",(0,i.jsx)(n.p,{children:"Who was it? It didn't take long to figure out."}),"\n",(0,i.jsx)(n.p,{children:'He went to Peter. Peter said, "You did good work. But the manufacturers have their own considerations. Cindy is following up on this. Let her handle it, she\'s familiar with this product line."'}),"\n",(0,i.jsx)(n.p,{children:'He went to the boss. The boss replied with a very short voice message: "These are minor issues. Don\'t be so calculating. We need colleagues to cooperate with each other."'}),"\n",(0,i.jsx)(n.p,{children:"Four walls. Every wall had an explanation. None of them were pointing a gun in his face."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming sat in his study and ran some calculations."}),"\n",(0,i.jsx)(n.p,{children:'If he insisted: What was he trying to prove? Who was he going to force to admit what? Qiang had his mouth sealed shut, and everyone had their explanations perfectly lined up. Even if the math was correct\u2014in this system, being "correct" wasn\'t enough.'}),"\n",(0,i.jsx)(n.p,{children:"There was another factor."}),"\n",(0,i.jsx)(n.p,{children:"Cindy was pregnant. He hadn't deliberately noticed it\u2014he saw it during a rare moment when she turned her camera on. She looked about seven or eight months along. After that, it was just the silence of a turned-off camera again. It was 2021 on Emerald Isle: the pandemic, closed borders, and housing prices at an all-time peak. She was pregnant, had a job, and this product line was her territory."}),"\n",(0,i.jsx)(n.p,{children:"If Lin Zhao-ming forced a collision\u2014an outsider three months into the job, fighting a pregnant woman over some credit?"}),"\n",(0,i.jsx)(n.p,{children:"Calculating the cost, it wasn't worth it."}),"\n",(0,i.jsx)(n.p,{children:"So he chose to say nothing."}),"\n",(0,i.jsx)(n.p,{children:"Things moved in the correct direction. Sharing cores was viable. This was a fact. He simply vanished his own name from the matter. The outcome itself was still good."}),"\n",(0,i.jsx)(n.p,{children:"This company possessed rationality. Even if it wasn't the kind of baseline he was familiar with, it was still a company that knew how to calculate. Wait until he understood more. Wait until he had a position of standing. He would address things then."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Everything that happened afterward, he watched as a bystander."}),"\n",(0,i.jsx)(n.p,{children:"There was a meeting about QCC integration that he wasn't CC'd on. He received a notification due to an administrative error, logged in halfway through, and sat quietly listening without his camera on."}),"\n",(0,i.jsx)(n.p,{children:'The people inside were discussing the core-sharing plan, using the tone of "exploring its feasibility." As if it hadn\'t already been run in a demo by Lin Zhao-ming, as if there were no hard numbers yet.'}),"\n",(0,i.jsx)(n.p,{children:'Someone asked, "Can we push it a bit higher? Achieve true modularity?"'}),"\n",(0,i.jsx)(n.p,{children:"Another voice replied, Cindy's: \"Only people without experience entertain thoughts like that. Stay here long enough, and you'll know that perfect compatibility is simply impossible.\""}),"\n",(0,i.jsx)(n.p,{children:'Lin Zhao-ming listened. He knew it could be done. He had run the math. But the other side offered no specific reasoning\u2014only the phrase, "you have no experience."'}),"\n",(0,i.jsx)(n.p,{children:"He logged off. No one knew he had been listening."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Sometime later, the big all-hands meeting took place."}),"\n",(0,i.jsx)(n.p,{children:"The plan was officially implemented, and someone presented the achievements of this new direction."}),"\n",(0,i.jsx)(n.p,{children:"The numbers used in the presentation\u2014he recognized them. Thirty iterations of electronic cores, reduced down to two. Thirty to two. He was the one who had originally calculated that number."}),"\n",(0,i.jsx)(n.p,{children:'But when he looked at the details of the plan\u2014there was no abstraction, no pushing for higher compatibility. They had simply slashed the thirty models down to the remaining two and slapped the label "Integration" on it.'}),"\n",(0,i.jsx)(n.p,{children:"It's fine for now, simply because they got lucky."}),"\n",(0,i.jsx)(n.p,{children:'The plan on the presentation slide was far more complex than his original version. Added steps, altered mechanisms\u2014not for improvement, but purely to add complexity. The kind of complexity that takes a perfectly viable straight path, twists it into a few detours, and then declares, "Look at how much of a journey I just walked."'}),"\n",(0,i.jsx)(n.p,{children:"He saw a shape he recognized, altered and then re-presented. He didn't know how to describe the feeling."}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming stayed in his grid box, camera off."}),"\n",(0,i.jsx)(n.p,{children:"It wasn't that he wasn't angry. It was that the anger coexisted with something else\u2014a feeling of, \"Oh, so this is how this system works.\""}),"\n",(0,i.jsx)(n.p,{children:"It wasn't understanding. It was simply the first time seeing that shape with total clarity."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"That night, his wife came to the door of his study."}),"\n",(0,i.jsx)(n.p,{children:'"Done with work?" she asked.'}),"\n",(0,i.jsx)(n.p,{children:'"Done," Lin Zhao-ming said.'}),"\n",(0,i.jsx)(n.p,{children:'"What were you working on?"'}),"\n",(0,i.jsx)(n.p,{children:"\"There was something they said couldn't be done before. I ran the numbers and saw it could be done. And now it's done.\""}),"\n",(0,i.jsx)(n.p,{children:'"That\'s a good thing, then."'}),"\n",(0,i.jsx)(n.p,{children:'"Yeah."'}),"\n",(0,i.jsx)(n.p,{children:"He didn't mention what happened after it was done. It wasn't that he didn't want to; it was because explaining it would require too much context\u2014who Cindy was, who Qiang was, who J was, what the under-the-table network was, and how a pregnant woman was related to all of it. Every individual piece wasn't a big deal on its own, but added together, it formed a massive entity, and he didn't know how to do the math to explain it, didn't know where to even begin."}),"\n",(0,i.jsx)(n.p,{children:'"Are you tired?" she asked.'}),"\n",(0,i.jsx)(n.p,{children:'"I\'m alright," Lin Zhao-ming said.'}),"\n",(0,i.jsx)(n.p,{children:"They each went about their own evenings."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"It was that very night, after his screen had gone black, that he remembered the incident at Peng Guang."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"\u2605 FLASHBACK A &lt;That Night, I Said No&gt;"}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"It was 2015, late at night, in the factory office."}),"\n",(0,i.jsx)(n.p,{children:'Mr. Zheng sat down and pushed a report in front of him. "The yield rate numbers here. Change them for me."'}),"\n",(0,i.jsx)(n.p,{children:"He looked at the numbers. The numbers were fake; anyone could tell at a glance."}),"\n",(0,i.jsx)(n.p,{children:'"I\'m not changing them."'}),"\n",(0,i.jsx)(n.p,{children:'Mr. Zheng looked at him. It was a calculating, evaluating gaze. "Think this through."'}),"\n",(0,i.jsx)(n.p,{children:'"I have."'}),"\n",(0,i.jsx)(n.p,{children:"Mr. Zheng stood up and walked away."}),"\n",(0,i.jsx)(n.p,{children:"The consequences came swiftly. His name disappeared from several projects. People began taking much longer to reply to his messages. He knew what the cost was. He accepted it."}),"\n",(0,i.jsx)(n.p,{children:"Uncle Zhai's incident had happened a few months prior to that."}),"\n",(0,i.jsx)(n.p,{children:"Uncle Zhai was a senior engineer in the production department. He had been there for over twenty years. On the morning the news broke, the factory opened as usual. Lin Zhao-ming walked past Uncle Zhai's desk\u2014perfectly neat and tidy. A newcomer was already sitting in his chair, making a phone call."}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming paused for a second. Then he kept walking."}),"\n",(0,i.jsx)(n.p,{children:"He had no direct connection to Uncle Zhai's death. But he had been inside that factory, watched how the factory had slowly transformed into what it was, and took absolutely no action."}),"\n",(0,i.jsx)(n.p,{children:"That time, he was a bystander."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"END FLASHBACK."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"The study, Emerald Isle, present day."}),"\n",(0,i.jsx)(n.p,{children:"That night, he had said no. The cost was entirely real, but he had been able to sleep that night."}),"\n",(0,i.jsx)(n.p,{children:"This time, he ran the calculations, and chose to say nothing."}),"\n",(0,i.jsx)(n.p,{children:"Were they the exact same thing?"}),"\n",(0,i.jsx)(n.p,{children:"He didn't know."}),"\n",(0,i.jsx)(n.p,{children:"He only knew one thing: This company was not the kind of company he thought it was. Not because there were bad people in it. It was because the rules of this place, and the tools he had brought into it, simply didn't belong to the same game."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.strong,{children:"ACT 2"})}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"March 2022."}),"\n",(0,i.jsx)(n.p,{children:"They accepted the awards, finished their performance, and everyone dispersed."}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming thought it was the end of it."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Then came that routine meeting."}),"\n",(0,i.jsx)(n.p,{children:"The boss was hosting. The whole team. Video call."}),"\n",(0,i.jsx)(n.p,{children:"No one had their cameras on. A row of grid boxes. Some had avatars, some had names, some were just pitch black."}),"\n",(0,i.jsx)(n.p,{children:"The boss spoke about everyone's performance, naming no names. \"Some people are doing exceptionally well. Some need improvement. Some people are assets to the team, and some people are burdens to the team.\" The tone was completely flat. It was the kind of tone where, after he finished speaking, you couldn't legally say he had said anything wrong, but you knew exactly what he was really talking about."}),"\n",(0,i.jsx)(n.p,{children:"Who was he referring to? No one knew. Everyone could claim it wasn't them. No names, no specific incidents, no details that anyone could press for further questioning."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"A few days later, J scheduled a one-on-one."}),"\n",(0,i.jsx)(n.p,{children:"They sat down, went through the pleasantries, and then J threw out his first sentence:"}),"\n",(0,i.jsx)(n.p,{children:'"What exactly did you say to the boss about me?"'}),"\n",(0,i.jsx)(n.p,{children:'Lin Zhao-ming sat there. "What do you mean?"'}),"\n",(0,i.jsx)(n.p,{children:'"The boss mentioned some things to me. I want to know your version of the story."'}),"\n",(0,i.jsx)(n.p,{children:"\"I haven't said anything to the boss about you. I don't know what he said.\""}),"\n",(0,i.jsx)(n.p,{children:"J nodded. He didn't press the matter further."}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming didn't press either."}),"\n",(0,i.jsx)(n.p,{children:"The call ended just like that."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"He sat in the study, staring at the black screen."}),"\n",(0,i.jsx)(n.p,{children:'"What exactly did you say to the boss about me."'}),"\n",(0,i.jsx)(n.p,{children:"It wasn't an accusation. It was a question. It was the kind of question where, after hearing it, you couldn't technically claim there was malice in the words, yet you knew there was something coiled tightly behind it."}),"\n",(0,i.jsx)(n.p,{children:'What had the boss said? How had J interpreted it? What were these "some things," and how did they travel from the boss, to J, and ultimately to Cindy?'}),"\n",(0,i.jsx)(n.p,{children:"He didn't know."}),"\n",(0,i.jsx)(n.p,{children:"In his previous companies, things like this would have been laid out on the table and talked out. But here, everything was WFH. Everything was text. Every call was simply white walls and grid boxes. It was an environment where you could never see the other person's expressions."}),"\n",(0,i.jsx)(n.p,{children:"Reading people was an art form he fundamentally never had to learn in his last job. At the American company, they spoke in numbers and results. If you hit your targets, you hit your targets; there was no guessing involved."}),"\n",(0,i.jsx)(n.p,{children:"But that was not how the game was played here."}),"\n",(0,i.jsx)(n.p,{children:"And he was only beginning to realize this months into the job\u2014not because anyone took the time to teach him, but because he was continuously smashing his face into it."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"After that, Cindy started targeting him."}),"\n",(0,i.jsx)(n.p,{children:'Not with a drawn knife in broad daylight. But in meetings, her rebuttals would pivot back to Lin Zhao-ming just a fraction of a second faster. In email threads, the phrasing carried something extra. It was something he could feel, but he couldn\'t grasp exactly what the "something" was.'}),"\n",(0,i.jsx)(n.p,{children:"It was the feeling of knowing something was definitively wrong, without being able to voice a single concrete, actionable piece of evidence."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:"Lin Zhao-ming didn't understand."}),"\n",(0,i.jsx)(n.p,{children:"He had already let it go. He hadn't filed a complaint, he hadn't sought retribution, he hadn't spoken a single word about any of this to anyone."}),"\n",(0,i.jsx)(n.p,{children:"So why was this happening?"}),"\n",(0,i.jsx)(n.p,{children:"Maybe the boss needed to ensure Cindy and J remained firmly in his camp. Maybe it was just his habit, his personal style of management. Maybe Lin Zhao-ming had said something that was misinterpreted in a completely unrelated setting he wasn't even aware of."}),"\n",(0,i.jsx)(n.p,{children:"Every explanation was possible."}),"\n",(0,i.jsx)(n.p,{children:"And every single explanation was utterly unconfirmable."}),"\n",(0,i.jsx)(n.p,{children:"He had deliberately chosen not to force a collision simply to keep the peace. Only to find himself violently dragged backward into an unseen battlefield."}),"\n",(0,i.jsx)(n.p,{children:"Dragged into what? Dragged for what reason? Who had decided he needed to be dragged?"}),"\n",(0,i.jsx)(n.p,{children:"He couldn't figure it out."}),"\n",(0,i.jsx)(n.p,{children:"He couldn't figure it out then, and he wouldn't figure it out later."}),"\n",(0,i.jsx)(n.hr,{}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.em,{children:"At the time, he thought this was simply the price a newcomer had to pay. He didn't understand the system yet; he hadn't secured a position yet. He thought things would be different once he had standing."})}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.em,{children:"But there was one thing he was slowly beginning to realize: This company was not the company he thought it was. Not because there were villains hiding in the shadows."})}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.em,{children:"It was because the game played here never used the deck of cards he had brought with him."})}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.em,{children:"And the most agonizing part wasn't losing."})}),"\n",(0,i.jsx)(n.p,{children:(0,i.jsx)(n.em,{children:"It was that he had zero idea that this was only the first round."})})]})}function c(e={}){const{wrapper:n}={...(0,a.R)(),...e.components};return n?(0,i.jsx)(n,{...e,children:(0,i.jsx)(l,{...e})}):l(e)}},8453(e,n,t){t.d(n,{R:()=>h,x:()=>o});var i=t(6540);const a={},s=i.createContext(a);function h(e){const n=i.useContext(s);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function o(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:h(e.components),i.createElement(s.Provider,{value:n},e.children)}}}]);